/// Find all nodes whose properties match all the given key-value pairs.
/// Since SQLite stores properties as JSON text, this iterates all nodes
/// and performs in-memory filtering — suitable for moderate-sized graphs.
pub fn find_nodes_by_properties(
    &self,
    properties: &HashMap<String, serde_json::Value>,
) -> Result<Vec<NodeAndEdge>> {
    with_db(&self.db, |conn| {
        let mut stmt = conn.prepare(
            "SELECT id, kind, name, properties, created_at FROM nodes ORDER BY created_at",
        )?;
        let rows = stmt.query_map([], row_to_node)?;
        let mut result = vec![];
        for row in rows {
            let node = row?;
            if properties
                .iter()
                .all(|(k, v)| node.properties.get(k) == Some(v))
            {
                result.push(NodeAndEdge {
                    node,
                    edge_kind: EdgeKind::DependsOn,
                });
            }
        }
        Ok(result)
    })
}

/// Paginated variant of `find_nodes_by_properties`.
/// Filters all nodes by properties, then applies limit/offset.
pub fn find_nodes_by_properties_paginated(
    &self,
    properties: &HashMap<String, serde_json::Value>,
    limit: usize,
    offset: usize,
) -> Result<Vec<NodeAndEdge>> {
    let all = self.find_nodes_by_properties(properties)?;
    let result: Vec<NodeAndEdge> = all.into_iter().skip(offset).take(limit).collect();
    Ok(result)
}

